-- 1. 태스크 생성
DECLARE
  v_task_name VARCHAR2(100) := 'seg_advisor_hr_employees';
  v_task_id   NUMBER;
  v_obj_id    NUMBER;
BEGIN
  -- 태스크 생성 (advisor_name: 'Segment Advisor')
  DBMS_ADVISOR.CREATE_TASK(
    advisor_name => 'Segment Advisor',
    task_name    => v_task_name,
    task_id      => v_task_id
  );
  -- 분석 대상 객체 추가
  DBMS_ADVISOR.CREATE_OBJECT(
    task_name   => v_task_name,
    object_type => 'TABLE',
    attr1       => 'HR',
    attr2       => 'EMPLOYEES',
    attr3       => NULL,
    attr4       => NULL,
    attr5       => NULL,
    object_id   => v_obj_id
  );
  -- 태스크 실행
  DBMS_ADVISOR.EXECUTE_TASK(task_name => v_task_name);
END;
/
-- 2. 결과 조회
SELECT task_name, type, message
FROM   dba_advisor_findings
WHERE  task_name = 'seg_advisor_hr_employees';

-- 1. 증분 통계 활성화
BEGIN
  DBMS_STATS.SET_TABLE_PREFS(
    ownname => 'SALES',
    tabname => 'ORDERS',
    pname   => 'INCREMENTAL',
    pvalue  => 'TRUE'
  );
END;
/
-- 2. 보류 통계 설정
BEGIN
  DBMS_STATS.SET_TABLE_PREFS(
    ownname => 'SALES',
    tabname => 'ORDERS',
    pname   => 'PUBLISH',
    pvalue  => 'FALSE'
  );
  -- 통계 수집 (보류 영역에 저장)
  DBMS_STATS.GATHER_TABLE_STATS('SALES', 'ORDERS');
END;
/
-- 3. 보류 통계 확인
SELECT * FROM dba_tab_pending_stats WHERE owner = 'SALES' AND table_name = 'ORDERS';
-- 4. 보류 통계로 실행 계획 테스트
ALTER SESSION SET OPTIMIZER_USE_PENDING_STATISTICS = TRUE;
EXPLAIN PLAN FOR SELECT * FROM sales.orders WHERE order_date > SYSDATE - 30;
SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY);
-- 5. 보류 통계 게시
BEGIN
  DBMS_STATS.PUBLISH_PENDING_STATS('SALES', 'ORDERS');
END;
/

-- 1. 테이블 통계 잠금
BEGIN
  DBMS_STATS.LOCK_TABLE_STATS('HR', 'EMPLOYEES');
END;
/
-- 2. 통계 잠금 상태 확인
SELECT table_name, stattype_locked
FROM   dba_tab_statistics
WHERE  owner = 'HR' AND table_name = 'EMPLOYEES';
-- 3. 통계 복원 (특정 시점으로)
BEGIN
  DBMS_STATS.RESTORE_TABLE_STATS(
    ownname      => 'HR',
    tabname      => 'EMPLOYEES',
    as_of_timestamp => SYSTIMESTAMP - INTERVAL '1' DAY,
    force        => TRUE  -- 잠긴 통계도 강제 복원
  );
END;
/
-- 4. 통계 기본 설정 조회
SELECT *
FROM   dba_tab_stat_prefs
WHERE  owner = 'HR';
-- 5. 노후화 임계값 변경
BEGIN
  DBMS_STATS.SET_TABLE_PREFS(
    ownname => 'HR',
    tabname => 'EMPLOYEES',
    pname   => 'STALE_PERCENT',
    pvalue  => '5'  -- 5%로 낮춤 (기본 10%)
  );
END;
/

-- 1. SQL_ID로 튜닝 태스크 생성
DECLARE
  v_task_name VARCHAR2(100);
BEGIN
  v_task_name := DBMS_SQLTUNE.CREATE_TUNING_TASK(
    sql_id      => 'g3yc9v4wsm71a',
    scope       => DBMS_SQLTUNE.SCOPE_COMPREHENSIVE,
    time_limit  => 300,
    task_name   => 'tune_sql_g3yc9v4wsm71a'
  );
  -- 2. 태스크 실행
  DBMS_SQLTUNE.EXECUTE_TUNING_TASK(task_name => v_task_name);
END;
/
-- 3. 튜닝 보고서 조회
SELECT DBMS_SQLTUNE.REPORT_TUNING_TASK(
  task_name => 'tune_sql_g3yc9v4wsm71a',
  type      => 'TEXT',
  level     => 'ALL',
  section   => 'ALL'
) AS report
FROM dual;

-- 1. SQL 프로파일 수락
BEGIN
  DBMS_SQLTUNE.ACCEPT_SQL_PROFILE(
    task_name   => 'tune_sql_g3yc9v4wsm71a',
    name        => 'profile_g3yc9v4wsm71a',
    category    => 'DEFAULT',
    force_match => TRUE,
    replace     => TRUE
  );
END;
/
-- 2. SQL 프로파일 목록 조회
SELECT name, sql_text, category, status, force_matching,
       created, last_modified, type
FROM   dba_sql_profiles
ORDER BY last_modified DESC;
-- 3. SQL 프로파일 비활성화
BEGIN
  DBMS_SQLTUNE.ALTER_SQL_PROFILE(
    name            => 'profile_g3yc9v4wsm71a',
    attribute_name  => 'STATUS',
    value           => 'DISABLED'
  );
END;
/
-- 4. SQL 프로파일 삭제
BEGIN
  DBMS_SQLTUNE.DROP_SQL_PROFILE(name => 'profile_g3yc9v4wsm71a');
END;
/

DECLARE
  v_task_name VARCHAR2(100) := 'access_advisor_task';
  v_task_id   NUMBER;
BEGIN
  -- 1. 태스크 생성
  DBMS_ADVISOR.CREATE_TASK(
    advisor_name => 'SQL Access Advisor',
    task_name    => v_task_name,
    task_id      => v_task_id
  );
  -- 2. STS를 워크로드로 연결
  DBMS_ADVISOR.ADD_STS_REF(
    task_name      => v_task_name,
    sts_owner      => 'SYS',
    sts_name       => 'my_workload_sts'
  );
  -- 3. 파라미터 설정
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name => v_task_name,
    parameter => 'ANALYSIS_SCOPE',
    value     => 'INDEX,MV'
  );
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name => v_task_name,
    parameter => 'MODE',
    value     => 'COMPREHENSIVE'
  );
  DBMS_ADVISOR.SET_TASK_PARAMETER(
    task_name => v_task_name,
    parameter => 'TIME_LIMIT',
    value     => 600
  );
  -- 4. 태스크 실행
  DBMS_ADVISOR.EXECUTE_TASK(task_name => v_task_name);
END;
/
-- 5. 보고서 조회
SELECT DBMS_ADVISOR.GET_TASK_REPORT(v_task_name, 'TEXT', 'ALL') AS report
FROM   dual;

-- 1. SPA 분석 태스크 생성 (STS 기반)
DECLARE
  v_task_name VARCHAR2(100);
BEGIN
  v_task_name := DBMS_SQLPA.CREATE_ANALYSIS_TASK(
    sqlset_name  => 'my_workload_sts',
    sqlset_owner => 'SYS',
    task_name    => 'spa_upgrade_test'
  );
  DBMS_OUTPUT.PUT_LINE('SPA Task Created: ' || v_task_name);
END;
/
-- 2. 변경 전 Trial 실행 (기준선 수집)
BEGIN
  DBMS_SQLPA.EXECUTE_ANALYSIS_TASK(
    task_name      => 'spa_upgrade_test',
    execution_type => 'TEST EXECUTE',
    execution_name => 'before_change'
  );
END;
/
-- 3. (시스템 변경 수행 후) 변경 후 Trial 실행
BEGIN
  DBMS_SQLPA.EXECUTE_ANALYSIS_TASK(
    task_name      => 'spa_upgrade_test',
    execution_type => 'TEST EXECUTE',
    execution_name => 'after_change'
  );
END;
/
-- 4. 변경 전후 비교 분석 실행
BEGIN
  DBMS_SQLPA.EXECUTE_ANALYSIS_TASK(
    task_name        => 'spa_upgrade_test',
    execution_type   => 'COMPARE PERFORMANCE',
    execution_name   => 'comparison',
    execution_params => DBMS_ADVISOR.ARGLIST(
      'execution_name1', 'before_change',
      'execution_name2', 'after_change',
      'comparison_metric', 'ELAPSED_TIME'
    )
  );
END;
/
-- 5. 비교 보고서 생성
SELECT DBMS_SQLPA.REPORT_ANALYSIS_TASK(
         task_name     => 'spa_upgrade_test',
         type          => 'TEXT',
         section       => 'ALL',
         execution_name => 'comparison'
       ) AS report
FROM   DUAL;
